var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"JANE_MASON_NULL_THIEF","text":{"KOREA":"흐음……. 강아지가 있다는 방이 여긴가?","JPN":"ふーん……仔犬がいる部屋ってここかしら？","ENG":"Hmm... Is this room where the puppy is?","TWN":"嗯……狗狗是在這個房間裡嗎？"},"stage":{"bg":"HALL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"JANE_MASON_NULL_THIEF","text":{"KOREA":"후훗. 문짝부터 아주 으리으리한데. 값 나가는 물건도 많겠어.","JPN":"フフッ、入口からお金の匂いがするわね。高く売れそうな物も多いみたいだし。","ENG":"Hah hah. Even the door looks luxurious. I bet this room is filled with expensive things.","TWN":"呵呵～光是一個房間門就這麼華麗，裡面應該有很多值錢的東西吧？"},"stage":{"bg":"HALL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"JANE_MASON_NULL_THIEF","text":{"KOREA":"일 마치고 돌아가는 길에 몇 개 슬쩍해도 모르겠지?","JPN":"仕事帰りにこっそり何個か持ち帰ってもバレなさそうね？","ENG":"No one would notice if I nabbed a few on my way out, would they?","TWN":"等我把事情辦完，回去時順手偷些東西，應該不會有人發現吧？"},"stage":{"bg":"HALL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"너에게 돌아갈 길은 없을 거다. 괴도 르블랑.","JPN":"あんたに持ち帰られるものなんてないぞ、怪盗ルブラン。","ENG":"Don't think you can go anywhere, LeBlanc the Thief.","TWN":"你確定你回得去嗎？怪盜布勒朗。"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"아니…….","JPN":"いや……","ENG":"Or...","TWN":"還是我應該叫你……"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"<color=#ffd34c>제인 도우</color>라고 해야 하나.","JPN":"<color=#ffd34c>ジェーン・ドウ</color>と呼ぶべきか。","ENG":"Should I call you <color=#ffd34c>Jane Doe</color>?","TWN":"<color=#ffd34c>珍妮·多伊</color>？"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"JANE_MASON_NULL_NULL","text":{"KOREA":"응? 이 목소리는……?","JPN":"あら？　この声は……？","ENG":"Mm? That voice...","TWN":"嗯？這個聲音是……？"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"JANE_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"나다. 설마 모른다고 하진 않겠지.","JPN":"俺だ。まさか知らないとは言わないだろう。","ENG":"It's me. Don't pretend you don't know me.","TWN":"是我，你應該不會不認得我吧！"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"보상금 들고 튈 때부터 알아봤어야 했는데…….","JPN":"報奨金を持ち逃げされた時に気付くべきだったが……","ENG":"I should have known when you ran away with my money.","TWN":"自從你捲款潛逃後，我早該打聽一下……"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"이제는 괴도라고? 아무리 불경기라지만 직업을 너무 함부로 고른 거 아닌가?","JPN":"怪盗だと？　いくら不景気とはいえ職業選びにこだわりが無さすぎじゃないか？","ENG":"You're a thief now, huh? Even if we're living in desperate times, shouldn't you be more careful in choosing your job?","TWN":"你現在是怪盜？就算再怎麼不景氣，你找工作是不是找得太隨便啦？"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"JANE_MASON_NULL_NULL","text":{"KOREA":"원래 진로를 결정하기 전에 이것저것 체험해 봐야 하지 않겠어?","JPN":"進路というのはね、決める前に色々と体験してみるべきなのよ。","ENG":"Shouldn't people at least try a few different things before choosing their career path?","TWN":"在決定出路前，不是本來就應該多嘗試嗎？"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"JANE_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"JANE_MASON_NULL_NULL","text":{"KOREA":"이번 건 꽤 적성에 맞는 것 같아서 고민 중이야.","JPN":"今回は結構性に合っているみたいで、悩んでいるの。","ENG":"I'm seriously thinking of staying at this job. I think it's my thing.","TWN":"這份的工作好像滿適合我的，所以我也滿苦惱的。 "},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"JANE_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"적성이고 나발이고 훔쳐간 보상금이나 내놔!","JPN":"性に合うもクソも無い、盗んでいった報奨金を返せ！","ENG":"Your thing or not, give me my money back!","TWN":"我管你適不適合，把我的獎金還來！"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"네가 보상금 들고 사라지는 바람에 우리 사무소는 길거리에 나앉게 생겼다고!","JPN":"あんたに報奨金を盗まれたせいで、事務所が破産寸前なんだぞ！","ENG":"Because you ran with my money, the business is on the verge of bankruptcy!","TWN":"都是因為你捲款潛逃，害我們事務所只能淪落街頭！"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"JANE_MASON_NULL_NULL","text":{"KOREA":"우리 사이에 섭섭하게 왜 그래. 내가 그 돈으로 나쁜 짓 할 여자 아닌 거 다 알면서.","JPN":"あら、そんな冷たいこと言わないでよ。アタシがあの金で悪いことをする女じゃないことくらい、知ってるでしょ？","ENG":"Come on, we've been through a lot together. You know I wouldn't do anything bad with your money.","TWN":"火氣幹嘛這麼大～你明知道我不會拿那筆錢去幹壞事～"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"JANE_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"그래. 그 돈 없어도 나쁜 짓 할 인간이긴 하지.","JPN":"そうだな。あの金がなくても悪いことをする人間だった。","ENG":"Well. I do know you'd do bad things with or without my money.","TWN":"沒錯，你就算沒有那筆錢，也會幹壞事！"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"JANE_MASON_NULL_NULL","text":{"KOREA":"칭찬 고마워, 동생.","JPN":"お褒めいただきありがとう、弟クン。","ENG":"Thank you, brother. I'll take that as a compliment.","TWN":"謝謝你的讚美，小老弟～"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"JANE_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"JANE_MASON_NULL_NULL","text":{"KOREA":"그나저나 이제 그만 자리 좀 비켜 줄래? 내 진로 선택에 방해가 되거든?","JPN":"ていうか、そろそろそこを退いてくれない？　アタシの進路選択の邪魔になるから。","ENG":"Now, could you get out my way? You're interfering with my career choice!","TWN":"不過你可以閃開嗎？你妨礙到姊姊的出路囉～"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"JANE_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};